// Basic try/catch/finally
function divide(a, b) {
  try {
    if (b === 0) throw new Error('Division by zero');
    const result = a / b;
    console.log(`Result: ${result}`);
    return result;
  } catch (err) {
    console.log(`Error: ${err.message}`);
    return null;
  } finally {
    console.log('Cleanup: always runs');
  }
}

divide(10, 2);
console.log('---');
divide(10, 0);

// finally runs even after return
