// Deep freeze utility
function deepFreeze(obj) {
  Object.freeze(obj);
  Object.values(obj).forEach(val => {
    if (typeof val === 'object' && val !== null) deepFreeze(val);
  });
  return obj;
}
const deep = deepFreeze({ a: { b: { c: 1 } } });
deep.a.b.c = 999;
console.log(deep.a.b.c); // still 1

