class Button {
  constructor(label) {
    this.label = label;
    this.clicks = 0;
    // Without bind, 'this' in handleClick would be the DOM element
    this.handleClick = this.handleClick.bind(this);
  }

  handleClick() {
    this.clicks++;
    console.log(`${this.label} clicked ${this.clicks} time(s)`);
  }
}

