    this.controller = new AbortController();

    try {
      const res = await fetch(`/api/search?q=${query}`, {
        signal: this.controller.signal
      });
      return await res.json();
    } catch (err) {
      if (err.name !== 'AbortError') throw err;
      console.log('Previous search cancelled');
    }
  }
}

